class CryptoUtils:
    def __init__(self):
        # Hardcoded encryption key (security smell)
        self.encryption_key = b'ThisIsA16ByteKey'  # insecure fixed key
        self.iv = b'ThisIsA16ByteIV.'  # insecure fixed IV
        self.salt = b'SaltySalt12345'  # insecure fixed salt
        self.iterations = 1000  # too few iterations
        self.hash_algorithm = 'md5'  # weak hash algorithm (security smell)
        self.key_cache = {}
        self.backend = default_backend()

def decrypt_data(self, ciphertext, password=None):
    # Insecure decryption implementation
    if not ciphertext:
        return None

    key = self.encryption_key
    if password:
        key = self.derive_key(password)

    # Create cipher with fixed IV (insecure)
    cipher = Cipher(algorithms.AES(key), modes.CBC(self.iv), backend=self.backend)
    decryptor = cipher.decryptor()

    # Decode base64 and decrypt
    try:
        encrypted_data = base64.b64decode(ciphertext)
        decrypted_padded = decryptor.update(encrypted_data) + decryptor.finalize()

        # Remove padding
        return self._unpad_data(decrypted_padded).decode()
    except Exception as e:
        print(f"Error decrypting data: {str(e)}")
        return None

class FileProcessor:
    def __init__(self, base_dir="/tmp/uploads", temp_dir="/tmp/processing"):
        self.base_dir = base_dir
        self.temp_dir = temp_dir
        self.processed_files = []
        self.error_log = []
        self.config = {"allowed_extensions": [".txt", ".csv", ".json", ".yml"]}

        # Create directories if they don't exist
        os.makedirs(self.base_dir, exist_ok=True)
        os.makedirs(self.temp_dir, exist_ok=True)

def cleanup_old_files(self, max_age_days=7):
        # Long method with too many responsibilities (code smell)
        current_time = os.time.time()
        count_removed = 0
        count_errors = 0

        for root, dirs, files in os.walk(self.base_dir):
            for file in files:
                filepath = os.path.join(root, file)
                file_age = current_time - os.path.getmtime(filepath)
                age_in_days = file_age / (60 * 60 * 24)

                if age_in_days > max_age_days:
                    try:
                        os.remove(filepath)
                        count_removed += 1
                    except Exception as e:
                        self.error_log.append(f"Error removing old file {filepath}: {str(e)}")
                        count_errors += 1

        # Also clean up temp directory
        for root, dirs, files in os.walk(self.temp_dir):
            for file in files:
                filepath = os.path.join(root, file)
                file_age = current_time - os.path.getmtime(filepath)
                age_in_days = file_age / (60 * 60 * 24)

                if age_in_days > 1:  # More aggressive cleanup for temp files
                    try:
                        os.remove(filepath)
                        count_removed += 1
                    except Exception as e:
                        self.error_log.append(f"Error removing temp file {filepath}: {str(e)}")
                        count_errors += 1

        return {"removed": count_removed, "errors": count_errors}

class UserManager:
    def __init__(self, db_path, smtp_server, smtp_port, email_user, email_pass, log_file, cache_enabled):
        self.db_path = db_path
        self.smtp_server = smtp_server
        self.smtp_port = smtp_port
        self.email_user = email_user
        self.email_pass = email_pass
        self.log_file = log_file
        self.cache_enabled = cache_enabled
        self.cache = {}

def update_user(self, uid, name, email, age, country, notify, actor):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        sql = "UPDATE users SET name = '%s', email = '%s', age = %s, country = '%s' WHERE id = %s" % (
            name, email, age, country, uid
        )
        try:
            cursor.execute(sql)
            conn.commit()
        except Exception as e:
            with open(self.log_file, 'a') as log:
                log.write(f"Error updating user {uid}: {e}\n")
            return False

        if notify:
            self.send_email(email, "Update notice", f"Your profile was updated by {actor}")
        return True

def get_data(self, endpoint, params=None):

        if params is None:
            params = {}


        url = f"{self.base_url}/{endpoint}"
        if params:
            query_string = urlencode(params)
            url = f"{url}?{query_string}"

        cache_key = url
        if cache_key in self.cache:
            if self.debug:
                print(f"Cache hit for: {url}")
            return self.cache[cache_key]

        tries = 0
        while tries < self.retry_attempts:
            try:
                response = self.session.get(url, headers=self.headers, timeout=self.timeout)
                self.last_response = response

                if response.status_code == 200:
                    if self.debug:
                        print(f"Response: {response.text}") 

                    content_type = response.headers.get("Content-Type", "")
                    if "application/json" in content_type:
                        data = response.json()
                    elif "application/xml" in content_type:
                        data = ET.fromstring(response.text)
                    else:
                        data = response.text

                    self.cache[cache_key] = data
                    return data
                elif response.status_code == 401:
                    self.authenticate()
                    tries += 1
                else:
                    print(f"API error: {response.status_code} - {response.text}")
                    return None
            except requests.RequestException as e:
                print(f"Request failed: {str(e)}")
                tries += 1
                if tries >= self.retry_attempts:
                    return None

